+    #[test]
+    fn cell_change_roundtrip_empty_content() {
+        use ftui_render::cell::CellContent;
+
+        let change = CellChange {
+            x: 0,
+            y: 0,
+            cell: Cell {
+                content: CellContent::EMPTY,
+                fg: PackedRgba::TRANSPARENT,
+                bg: PackedRgba::TRANSPARENT,
+                attrs: CellAttrs::NONE,
+            },
+        };
